noncompliant:
// Double locking the same mutex
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void double_lock_example() {
    pthread_mutex_lock(&mutex);
    // ... some work
    pthread_mutex_lock(&mutex);    // Noncompliant: already locked
    pthread_mutex_unlock(&mutex);
    pthread_mutex_unlock(&mutex);
}

// Double unlocking the same mutex
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void double_unlock_example() {
    pthread_mutex_lock(&mutex);
    pthread_mutex_unlock(&mutex);
    pthread_mutex_unlock(&mutex);  // Noncompliant: already unlocked
}

// Unlocking without locking
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void unlock_without_lock() {
    // No lock call
    pthread_mutex_unlock(&mutex);  // Noncompliant: never locked
}

compliant:
// Proper mutex usage - single lock/unlock pair
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
int shared_data = 0;

void proper_mutex_usage() {
    pthread_mutex_lock(&mutex);    // Compliant: lock once
    shared_data++;                 // Critical section
    pthread_mutex_unlock(&mutex);  // Compliant: unlock once
}

// Proper nested function calls with mutex
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void helper_function() {
    // This function assumes mutex is already locked
    // Does not lock/unlock itself
    // ... work on shared data
}

void main_function() {
    pthread_mutex_lock(&mutex);    // Compliant: single lock
    helper_function();             // Safe to call
    pthread_mutex_unlock(&mutex);  // Compliant: single unlock
}

// Using trylock to avoid blocking
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void safe_trylock_usage() {
    if (pthread_mutex_trylock(&mutex) == 0) {  // Compliant
        // Got the lock, do work
        // ... critical section
        pthread_mutex_unlock(&mutex);  // Compliant: unlock after successful lock
    } else {
        // Could not get lock, handle gracefully
        printf("Could not acquire mutex\n");
    }
}
